<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Falling Sand Sandbox</title>
<style>
  :root{
    --bg:#0b0d12; --panel:#151922; --edge:#232838; --txt:#c9d1e0;
    --accent:#5b8def;
  }
  *{box-sizing:border-box;}
  html,body{height:100%;}
  body{
    margin:0; background:radial-gradient(1200px 800px at 50% -10%,#141a26,var(--bg));
    color:var(--txt);
    font-family:ui-sans-serif,system-ui,Segoe UI,Roboto,Helvetica,Arial,sans-serif;
    display:flex; flex-direction:column; align-items:center; justify-content:center;
    gap:18px; padding:24px; min-height:100vh;
  }
  h1{font-size:15px; letter-spacing:.14em; text-transform:uppercase; font-weight:600;
     color:#8b95ab; margin:0;}
  .stage{
    padding:14px; background:var(--panel); border:1px solid var(--edge);
    border-radius:14px; box-shadow:0 20px 60px rgba(0,0,0,.5), inset 0 0 0 1px rgba(255,255,255,.02);
  }
  #sand{
    display:block; width:500px; height:500px; image-rendering:pixelated;
    border-radius:8px; background:#05060a; cursor:crosshair;
    border:1px solid #0d1017; touch-action:none;
  }
  .bar{display:flex; gap:10px; flex-wrap:wrap; justify-content:center; max-width:540px;}
  button{
    appearance:none; cursor:pointer; color:var(--txt);
    background:var(--panel); border:1px solid var(--edge);
    padding:9px 15px; border-radius:10px; font-size:13px; font-weight:500;
    display:flex; align-items:center; gap:8px; transition:.12s ease;
    user-select:none;
  }
  button:hover{border-color:#39415a; transform:translateY(-1px);}
  button:active{transform:translateY(0);}
  button .sw{width:13px; height:13px; border-radius:3px; box-shadow:inset 0 0 0 1px rgba(0,0,0,.35);}
  button.active{border-color:var(--accent); box-shadow:0 0 0 1px var(--accent), 0 6px 18px rgba(91,141,239,.25);}
  #clear{border-color:#5a2530; color:#f0b3bb;}
  #clear:hover{border-color:#8a3542;}
  .hint{font-size:12px; color:#5c667c;}
</style>
</head>
<body>
  <h1>Falling&nbsp;Sand&nbsp;Sandbox</h1>
  <div class="stage"><canvas id="sand" width="500" height="500"></canvas></div>
  <div class="bar">
    <button id="mat-sand"  class="active" data-mat="sand"><span class="sw" style="background:#d9b06a"></span>Sand</button>
    <button id="mat-water" data-mat="water"><span class="sw" style="background:#3a7bd5"></span>Water</button>
    <button id="mat-wall"  data-mat="wall"><span class="sw" style="background:#6b7280"></span>Wall</button>
    <button id="mat-acid"  data-mat="acid"><span class="sw" style="background:#7cfc00"></span>Acid</button>
    <button id="mat-empty" data-mat="empty"><span class="sw" style="background:#05060a"></span>Eraser</button>
    <button id="clear">Clear</button>
  </div>
  <div class="hint">Drag on the canvas to paint the selected material.</div>

<script>
(() => {
  // ---- material codes ----
  const EMPTY=0, SAND=1, WATER=2, WALL=3, ACID=4;
  const NAME = {0:"empty",1:"sand",2:"water",3:"wall",4:"acid"};
  const CODE = {empty:EMPTY,sand:SAND,water:WATER,wall:WALL,acid:ACID};

  const W = 100, H = 100;            // grid cells (>= 80x80)
  const grid  = new Uint8Array(W*H);
  const moved = new Uint8Array(W*H); // per-step one-move-only guard

  // ---- helpers ----
  const inB = (x,y) => x>=0 && x<W && y>=0 && y<H;
  const idxOf = (x,y) => y*W + x;

  function move(from, to){ grid[to]=grid[from]; grid[from]=EMPTY; moved[to]=1; }
  function swap(from, to){ const t=grid[from]; grid[from]=grid[to]; grid[to]=t; moved[to]=1; moved[from]=1; }

  const isLiquid = c => c===WATER || c===ACID;

  // ---- per-cell rules ----
  function doSand(x,y,i){
    const by = y+1;
    if (by >= H) return;                      // floor
    const b = i+W;
    if (grid[b]===EMPTY){ move(i,b); return; }
    if (isLiquid(grid[b]) && !moved[b]){ swap(i,b); return; }   // sink, capped 1 cell/step
    const dirs = Math.random()<0.5 ? [-1,1] : [1,-1];
    for (const dx of dirs){
      const nx=x+dx; if (nx<0||nx>=W) continue;
      const d=b+dx;
      if (grid[d]===EMPTY){ move(i,d); return; }
      if (isLiquid(grid[d]) && !moved[d]){ swap(i,d); return; }
    }
  }

  function doWater(x,y,i){
    const by=y+1, b=i+W;
    if (by < H){
      if (grid[b]===EMPTY){ move(i,b); return; }
      const dirs = Math.random()<0.5 ? [-1,1] : [1,-1];
      for (const dx of dirs){
        const nx=x+dx; if (nx<0||nx>=W) continue;
        const d=b+dx;
        if (grid[d]===EMPTY){ move(i,d); return; }
      }
    }
    // spread horizontally
    const dirs = Math.random()<0.5 ? [-1,1] : [1,-1];
    for (const dx of dirs){
      const nx=x+dx; if (nx<0||nx>=W) continue;
      const s=i+dx;
      if (grid[s]===EMPTY){ move(i,s); return; }
    }
  }

  function doAcid(x,y,i){
    // dissolve a sand/wall neighbour (below, then sides)
    const cand=[];
    if (y+1<H) cand.push(i+W);
    if (x>0)   cand.push(i-1);
    if (x<W-1) cand.push(i+1);
    for (const c of cand){
      const g=grid[c];
      if (g===SAND || g===WALL){
        grid[c]=EMPTY;                         // walls erode
        if (Math.random()<0.14){ grid[i]=EMPTY; moved[i]=1; return; } // acid sometimes spent
        break;                                 // one bite per step
      }
    }
    // then move like water
    doWater(x,y,i);
  }

  // ---- one simulation step: bottom row up ----
  function step(){
    moved.fill(0);
    for (let y=H-1; y>=0; y--){
      const ltr = Math.random()<0.5;
      for (let k=0; k<W; k++){
        const x = ltr ? k : (W-1-k);
        const i = idxOf(x,y);
        if (moved[i]) continue;
        const t = grid[i];
        if (t===EMPTY || t===WALL) continue;
        if      (t===SAND)  doSand(x,y,i);
        else if (t===WATER) doWater(x,y,i);
        else if (t===ACID)  doAcid(x,y,i);
      }
    }
  }

  // ---- rendering ----
  const canvas = document.getElementById("sand");
  const ctx = canvas.getContext("2d");
  ctx.imageSmoothingEnabled = false;
  const off = document.createElement("canvas");
  off.width=W; off.height=H;
  const octx = off.getContext("2d");
  const img = octx.createImageData(W,H);

  // packed RGBA colors
  const COL = {
    [EMPTY]:[5,6,10], [SAND]:[217,176,106], [WATER]:[58,123,213],
    [WALL]:[107,114,128], [ACID]:[124,252,0]
  };
  function render(){
    const d = img.data;
    for (let i=0;i<W*H;i++){
      const c = COL[grid[i]];
      const p=i*4;
      d[p]=c[0]; d[p+1]=c[1]; d[p+2]=c[2]; d[p+3]=255;
    }
    octx.putImageData(img,0,0);
    ctx.clearRect(0,0,canvas.width,canvas.height);
    ctx.drawImage(off,0,0,canvas.width,canvas.height);
  }

  function frame(){ step(); render(); requestAnimationFrame(frame); }
  requestAnimationFrame(frame);

  // ---- painting ----
  let current = SAND;
  let painting = false;
  const BRUSH = 2; // radius

  function paintAt(clientX, clientY){
    const r = canvas.getBoundingClientRect();
    const gx = Math.floor((clientX - r.left) / r.width  * W);
    const gy = Math.floor((clientY - r.top ) / r.height * H);
    for (let dy=-BRUSH; dy<=BRUSH; dy++){
      for (let dx=-BRUSH; dx<=BRUSH; dx++){
        if (dx*dx+dy*dy > BRUSH*BRUSH+1) continue;
        const x=gx+dx, y=gy+dy;
        if (inB(x,y)) grid[idxOf(x,y)] = current;
      }
    }
  }

  canvas.addEventListener("mousedown", e=>{ painting=true; paintAt(e.clientX,e.clientY); });
  window.addEventListener("mousemove", e=>{ if(painting) paintAt(e.clientX,e.clientY); });
  window.addEventListener("mouseup", ()=> painting=false);
  canvas.addEventListener("touchstart", e=>{ painting=true; const t=e.touches[0]; paintAt(t.clientX,t.clientY); e.preventDefault(); }, {passive:false});
  canvas.addEventListener("touchmove", e=>{ if(painting){ const t=e.touches[0]; paintAt(t.clientX,t.clientY);} e.preventDefault(); }, {passive:false});
  window.addEventListener("touchend", ()=> painting=false);

  // ---- material buttons ----
  const matBtns = document.querySelectorAll("button[data-mat]");
  matBtns.forEach(btn=>{
    btn.addEventListener("click", ()=>{
      current = CODE[btn.dataset.mat];
      matBtns.forEach(b=>b.classList.remove("active"));
      btn.classList.add("active");
    });
  });

  document.getElementById("clear").addEventListener("click", ()=> grid.fill(EMPTY));

  // ---- programmatic API ----
  window.sim = {
    w: W, h: H,
    tick(n){ n = (n|0); for (let s=0;s<n;s++) step(); },
    get(x,y){ return inB(x,y) ? NAME[grid[idxOf(x,y)]] : "wall"; },
    set(x,y,mat){ if(inB(x,y) && mat in CODE) grid[idxOf(x,y)] = CODE[mat]; },
    clear(){ grid.fill(EMPTY); }
  };
})();
</script>
</body>
</html>
